array_types.code:
type Register_Array is
   array (Register_Count_Type range <>)
   of Register_Digit_Array;

subtypes.code:
subtype Hex_String is Wide_String (1 .. Digits_Per_Register) with
      Dynamic_Predicate =>
       (for all I in Hex_String'Range => (Hex_String (I) in '0' .. '9' | 'A' .. 'F' | 'a' .. 'f'));

subtype Null_Register_Digit_Array is Register_Digit_Array with
      Dynamic_Predicate =>
       (for all I in Null_Register_Digit_Array'Range => (Null_Register_Digit_Array (I) = Digit_Type'(16#0#)));

